import java.util.*;

public class GracefulShutdownHandler {

    private volatile boolean shuttingDown = false;
    private int activeRequests = 0;
    private final List<Runnable> shutdownHooks = new ArrayList<>();

    public synchronized void onRequestStart() {
        if (shuttingDown) {
            throw new IllegalStateException("Server is shutting down");
        }
        activeRequests++;
    }

    public synchronized void onRequestEnd() {
        activeRequests--;
    }

    public void registerShutdownHook(Runnable hook) {
        shutdownHooks.add(hook);
    }

    public ShutdownResult initiateShutdown(int timeoutMs) {
        shuttingDown = true;
        // Simulate waiting: poll activeRequests until 0 or timeout
        long start = System.currentTimeMillis();
        while (activeRequests > 0) {
            if (System.currentTimeMillis() - start > timeoutMs) {
                return runHooksAndReturn(false, activeRequests);
            }
            try { Thread.sleep(10); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        }
        return runHooksAndReturn(true, 0);
    }

    private ShutdownResult runHooksAndReturn(boolean graceful, int remainingRequests) {
        // Run hooks in reverse registration order
        List<String> executedHooks = new ArrayList<>();
        // TODO: run shutdownHooks in reverse order, collecting hook toString or a label
        return new ShutdownResult(graceful, remainingRequests, executedHooks);
    }

    public record ShutdownResult(boolean graceful, int remainingRequests, List<String> executedHooks) {}

    public boolean isShuttingDown() { return shuttingDown; }

    public static void main(String[] args) {
        GracefulShutdownHandler handler = new GracefulShutdownHandler();
        List<String> log = new ArrayList<>();

        handler.registerShutdownHook(() -> log.add("Close DB connections"));
        handler.registerShutdownHook(() -> log.add("Flush message queue"));
        handler.registerShutdownHook(() -> log.add("Stop scheduled tasks"));

        handler.onRequestStart();
        handler.onRequestEnd(); // all requests done

        ShutdownResult result = handler.initiateShutdown(100);
        System.out.println("Graceful: " + result.graceful());
        System.out.println("Hooks run: " + log.size());
        System.out.println("Order: " + log); // reverse order expected

        try {
            handler.onRequestStart(); // should throw
        } catch (IllegalStateException e) {
            System.out.println("Rejected: " + e.getMessage());
        }
    }
}

import java.util.*;

public class FeatureFlagManager {

    public record FeatureFlag(
        String name,
        boolean globalEnabled,
        Set<String> enabledForUsers,
        int rolloutPercent
    ) {}

    private final Map<String, FeatureFlag> flags = new HashMap<>();

    public void registerFlag(String name, boolean globalEnabled,
                              Set<String> enabledForUsers, int rolloutPercent) {
        flags.put(name, new FeatureFlag(name, globalEnabled,
                                        new HashSet<>(enabledForUsers), rolloutPercent));
    }

    public boolean isEnabled(String featureName, String userId) {
        FeatureFlag flag = flags.get(featureName);
        if (flag == null) return false;

        // Check in order:
        // 1. Global flag
        // 2. User-specific whitelist
        // 3. Percentage rollout based on userId hash
        if (flag.globalEnabled()) return true;
        if (flag.enabledForUsers().contains(userId)) return true;

        // Rollout: use abs(userId.hashCode()) % 100 < rolloutPercent
        int bucket = Math.abs(userId.hashCode()) % 100;
        return bucket < flag.rolloutPercent();
    }

    public List<String> enabledFeaturesFor(String userId) {
        // Return names of all features enabled for the user
        return new ArrayList<>(); // TODO
    }

    public static void main(String[] args) {
        FeatureFlagManager manager = new FeatureFlagManager();

        manager.registerFlag("new-checkout", false, Set.of("beta-user-1"), 0);
        manager.registerFlag("dark-mode", true, Set.of(), 0);
        manager.registerFlag("ai-search", false, Set.of(), 50);

        System.out.println("beta-user-1 new-checkout: " + manager.isEnabled("new-checkout", "beta-user-1"));
        System.out.println("regular-user new-checkout: " + manager.isEnabled("new-checkout", "regular-user"));
        System.out.println("dark-mode: " + manager.isEnabled("dark-mode", "anyone"));
        System.out.println("Known features for beta-user-1: " + manager.enabledFeaturesFor("beta-user-1").size());
    }
}

import java.util.*;
import java.util.function.Supplier;

public class RetryExecutor {

    private final int maxAttempts;
    private final long baseDelayMs;
    private final long maxDelayMs;

    public RetryExecutor(int maxAttempts, long baseDelayMs, long maxDelayMs) {
        this.maxAttempts = maxAttempts;
        this.baseDelayMs = baseDelayMs;
        this.maxDelayMs = maxDelayMs;
    }

    public long calculateDelay(int attemptNumber) {
        // Exponential backoff: min(2^attemptNumber * baseDelayMs, maxDelayMs)
        long delay = (long) Math.pow(2, attemptNumber) * baseDelayMs;
        return Math.min(delay, maxDelayMs);
    }

    public <T> RetryResult<T> execute(Supplier<T> operation) {
        List<String> errors = new ArrayList<>();
        for (int attempt = 0; attempt < maxAttempts; attempt++) {
            try {
                T result = operation.get();
                return new RetryResult<>(result, attempt + 1, errors, true);
            } catch (Exception e) {
                errors.add("Attempt " + (attempt + 1) + " failed: " + e.getMessage());
                // In a real implementation, we'd sleep here. Skip sleeping for testability.
            }
        }
        return new RetryResult<>(null, maxAttempts, errors, false);
    }

    public record RetryResult<T>(
        T value,
        int attemptsUsed,
        List<String> errors,
        boolean succeeded
    ) {}

    public static void main(String[] args) {
        RetryExecutor executor = new RetryExecutor(4, 100, 5000);

        System.out.println("Delay attempt 0: " + executor.calculateDelay(0) + "ms");
        System.out.println("Delay attempt 3: " + executor.calculateDelay(3) + "ms");
        System.out.println("Delay attempt 10 (capped): " + executor.calculateDelay(10) + "ms");

        int[] callCount = {0};
        RetryResult<String> result = executor.execute(() -> {
            callCount[0]++;
            if (callCount[0] < 3) throw new RuntimeException("Service unavailable");
            return "Success on attempt " + callCount[0];
        });

        System.out.println("Succeeded: " + result.succeeded());
        System.out.println("Attempts: " + result.attemptsUsed());
        System.out.println("Value: " + result.value());
    }
}
